import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Cell } from 'recharts';
import { ArrowRight, TrendingUp, TrendingDown, Minus } from 'lucide-react';

const API_BASE_URL = "http://127.0.0.1:5000/api";

const Compare = () => {
    const userId = localStorage.getItem('userId');
    const [datasets, setDatasets] = useState([]);
    const [id1, setId1] = useState('');
    const [id2, setId2] = useState('');
    const [result, setResult] = useState(null);
    const [loading, setLoading] = useState(false);

    // 1. Fetch File List
    useEffect(() => {
        axios.get(`${API_BASE_URL}/user-datasets`, { headers: { 'X-User-ID': userId } })
            .then(res => setDatasets(res.data))
            .catch(err => console.error(err));
    }, [userId]);

    // 2. Run Comparison
    const handleCompare = async () => {
        if (!id1 || !id2) return alert("Please select two files to compare.");
        setLoading(true);
        try {
            // Run both audits in parallel
            const [res1, res2] = await Promise.all([
                axios.get(`${API_BASE_URL}/analyze/${id1}`, { headers: { 'X-User-ID': userId } }),
                axios.get(`${API_BASE_URL}/analyze/${id2}`, { headers: { 'X-User-ID': userId } })
            ]);

            const d1 = res1.data.summary;
            const d2 = res2.data.summary;
            const meta1 = datasets.find(d => d.dataset_id === parseInt(id1));
            const meta2 = datasets.find(d => d.dataset_id === parseInt(id2));

            // Calculate % Change
            const diff = d2.total_emissions - d1.total_emissions;
            const pct = d1.total_emissions > 0 ? (diff / d1.total_emissions) * 100 : 0;

            setResult({
                name1: meta1.filename,
                name2: meta2.filename,
                data1: d1,
                data2: d2,
                diff: diff,
                pct: pct
            });
        } catch (error) {
            alert("Error analyzing files. Please try again.");
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    // Chart Data Preparation
    const getChartData = () => {
        if (!result) return [];
        return [
            { name: 'Total Emissions', v1: result.data1.total_emissions, v2: result.data2.total_emissions },
            { name: 'Scope 1 (Diesel)', v1: result.data1.scope1, v2: result.data2.scope1 },
            { name: 'Scope 2 (Elec)', v1: result.data1.scope2, v2: result.data2.scope2 },
            { name: 'Net Gap', v1: result.data1.net_gap, v2: result.data2.net_gap },
        ];
    };

    return (
        <div style={{ padding: '30px', maxWidth: '1200px', margin: '0 auto' }}>
            <h2 style={{ color: '#1b5e20', marginBottom: '30px' }}>⚖️ Compare Years</h2>

            {/* CONTROL PANEL */}
            <div style={{ background: 'white', padding: '30px', borderRadius: '12px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', display: 'grid', gridTemplateColumns: '1fr auto 1fr auto', gap: '20px', alignItems: 'end', marginBottom: '30px' }}>
                <div>
                    <label style={labelStyle}>Baseline Year (A)</label>
                    <select style={selectStyle} value={id1} onChange={e => setId1(e.target.value)}>
                        <option value="">-- Select File --</option>
                        {datasets.map(d => <option key={d.dataset_id} value={d.dataset_id}>{d.filename}</option>)}
                    </select>
                </div>

                <div style={{ paddingBottom: '10px', color: '#999' }}><ArrowRight /></div>

                <div>
                    <label style={labelStyle}>Comparison Year (B)</label>
                    <select style={selectStyle} value={id2} onChange={e => setId2(e.target.value)}>
                        <option value="">-- Select File --</option>
                        {datasets.map(d => <option key={d.dataset_id} value={d.dataset_id}>{d.filename}</option>)}
                    </select>
                </div>

                <button onClick={handleCompare} disabled={loading} style={btnStyle}>
                    {loading ? 'Analyzing...' : 'Run Comparison'}
                </button>
            </div>

            {/* RESULTS AREA */}
            {result && (
                <div style={{ animation: 'fadeIn 0.5s' }}>
                    
                    {/* STAT CARDS */}
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '20px', marginBottom: '30px' }}>
                        
                        {/* CHANGE CARD */}
                        <div style={{ ...cardStyle, borderTop: `4px solid ${result.pct > 0 ? '#ef5350' : '#66bb6a'}` }}>
                            <div style={{ display:'flex', alignItems:'center', gap:'10px', color:'#666', fontSize:'0.9rem' }}>
                                {result.pct > 0 ? <TrendingUp size={18} color="#ef5350"/> : result.pct < 0 ? <TrendingDown size={18} color="#66bb6a"/> : <Minus size={18}/>}
                                Total Change
                            </div>
                            <div style={{ fontSize: '2.5rem', fontWeight: 'bold', color: result.pct > 0 ? '#c62828' : '#2e7d32', margin: '10px 0' }}>
                                {result.pct > 0 ? '+' : ''}{result.pct.toFixed(1)}%
                            </div>
                            <div style={{ color: '#888', fontSize: '0.9rem' }}>
                                {Math.abs(result.diff).toFixed(1)} tCO₂e difference
                            </div>
                        </div>

                        {/* BASELINE CARD */}
                        <div style={cardStyle}>
                            <div style={{ color: '#888', fontSize: '0.9rem' }}>Baseline ({result.name1})</div>
                            <div style={{ fontSize: '1.8rem', fontWeight: 'bold', color: '#333', marginTop:'10px' }}>
                                {result.data1.total_emissions.toFixed(0)} <span style={{fontSize:'1rem'}}>tCO₂e</span>
                            </div>
                        </div>

                        {/* CURRENT CARD */}
                        <div style={cardStyle}>
                            <div style={{ color: '#888', fontSize: '0.9rem' }}>Comparison ({result.name2})</div>
                            <div style={{ fontSize: '1.8rem', fontWeight: 'bold', color: '#333', marginTop:'10px' }}>
                                {result.data2.total_emissions.toFixed(0)} <span style={{fontSize:'1rem'}}>tCO₂e</span>
                            </div>
                        </div>
                    </div>

                    {/* CHART */}
                    <div style={{ background: 'white', padding: '30px', borderRadius: '12px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)' }}>
                        <h4 style={{ textAlign: 'center', marginBottom: '30px', color:'#444' }}>Side-by-Side Performance</h4>
                        <ResponsiveContainer width="100%" height={400}>
                            <BarChart data={getChartData()} margin={{top: 20, right: 30, left: 20, bottom: 5}}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                                <XAxis dataKey="name" />
                                <YAxis />
                                <Tooltip cursor={{fill: 'transparent'}} />
                                <Legend />
                                <Bar dataKey="v1" name="Baseline (A)" fill="#bdbdbd" radius={[4,4,0,0]} />
                                <Bar dataKey="v2" name="Comparison (B)" fill="#1976d2" radius={[4,4,0,0]} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>

                </div>
            )}
        </div>
    );
};

// Styles
const labelStyle = { display: 'block', marginBottom: '8px', fontWeight: 'bold', color: '#555', fontSize: '0.9rem' };
const selectStyle = { width: '100%', padding: '12px', borderRadius: '6px', border: '1px solid #ccc', fontSize: '14px' };
const btnStyle = { padding: '12px 30px', background: '#2e7d32', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold', fontSize: '16px', height: '45px' };
const cardStyle = { background: 'white', padding: '25px', borderRadius: '12px', boxShadow: '0 2px 8px rgba(0,0,0,0.05)', textAlign: 'center' };

export default Compare;
